"innerContent\":{\"desktop\":{\"value\":\"kjb rn.\"}},\"decoration\":{\"font\":{\"font\":{\"desktop\":{\"value\":{\"family\":\"var(\\u002d\\u002det_global_heading_font)\",\"weight\":\"700\",\"style\":[\"italic\"],\"color\":\"#c9972a\",\"size\":\"28px\"}}}}}},\"builderVersion\":\"4.27.6\",\"modulePreset\":[\"default\"],\"module\":{\"decoration\":{\"background\":{\"desktop\":{\"value\":{\"color\":\"#1b1f3b\",\"enableColor\":\"on\"}}}},\"advanced\":{\"text\":{\"text\":{\"desktop\":{\"value\":{\"orientation\":\"center\"}}}}}},\"content\":{\"decoration\":{\"spacing\":{\"desktop\":{\"value\":{\"padding\":{\"top\":\"50px\",\"right\":\"\",\"bottom\":\"100px\",\"left\":\"\",\"syncVertical\":\"off\",\"syncHorizontal\":\"off\"}}}}},\"innerContent\":{\"desktop\":{\"value\":\"\\u003cp\\u003eDr. Abrina is the best! I highly recommend her! She and her staff have been wonderful to me. I’ve called her office so many times with questions and they’ve always been kind, patient, and understanding.\\u003c/p\\u003e\"}}}} --><!-- /wp:divi/slide --><!-- wp:divi/slide {\"title\":{\"innerContent\":{\"desktop\":{\"value\":\"Robyn cote.\"}},\"decoration\":{\"font\":{\"font\":{\"desktop\":{\"value\":{\"family\":\"var(\\u002d\\u002det_global_heading_font)\",\"weight\":\"700\",\"style\":[\"italic\"],\"color\":\"#c9972a\",\"size\":\"28px\"}}}}}},\"builderVersion\":\"4.27.6\",\"modulePreset\":[\"default\"],\"module\":{\"decoration\":{\"background\":{\"desktop\":{\"value\":{\"color\":\"#1b1f3b\",\"enableColor\":\"on\"}}}},\"advanced\":{\"text\":{\"text\":{\"desktop\":{\"value\":{\"orientation\":\"center\"}}}}}},\"content\":{\"decoration\":{\"spacing\":{\"desktop\":{\"value\":{\"padding\":{\"top\":\"50px\",\"right\":\"\",\"bottom\":\"100px\",\"left\":\"\",\"syncVertical\":\"off\",\"syncHorizontal\":\"off\"}}}}},\"innerContent\":{\"desktop\":{\"value\":\"\\u003cp\\u003eShe is a great doctor as well as Dr Kumar. I’ve been complaining about the same problems for years with my old primary. She listened, p